def gerar_clausula_residencial(imovel):
    tipo   = imovel.get("tipo_imovel","imóvel")
    area   = imovel.get("area","")
    mob    = imovel.get("mobiliado","Não")
    mat    = imovel.get("matricula","")
    mat_txt = f", matriculado sob nº {mat}," if mat else ""
    area_txt = f" com área de {area}m²" if area else ""
    return f"""CLÁUSULA DE DESTINAÇÃO DO IMÓVEL
O imóvel objeto da presente locação{mat_txt} do tipo {tipo}{area_txt}, é destinado exclusivamente para fins residenciais, sendo vedada qualquer atividade comercial, industrial ou de prestação de serviços, nos termos da Lei nº 8.245/91.
O imóvel é entregue {f'mobiliado ({mob.lower()})' if mob != 'Não' else 'sem mobília'}, conforme descrito no Termo de Vistoria Inicial anexo.
Nota: Descrição baseada nas informações e imagens fornecidas pelas partes."""

def gerar_clausula_comercial(imovel):
    tipo      = imovel.get("tipo_imovel","imóvel comercial")
    area      = imovel.get("area","")
    atividade = imovel.get("atividade_permitida","a ser definida")
    cnae      = imovel.get("cnae","")
    uso_pesado = imovel.get("uso_pesado", False)
    mat       = imovel.get("matricula","")
    mat_txt   = f", matriculado sob nº {mat}," if mat else ""
    area_txt  = f" com área de {area}m²" if area else ""
    cnae_txt  = f" (CNAE: {cnae})" if cnae else ""
    clausula  = f"""CLÁUSULA DE DESTINAÇÃO DO IMÓVEL
O imóvel objeto da presente locação{mat_txt} do tipo {tipo}{area_txt}, destina-se ao exercício da atividade de {atividade}{cnae_txt}, sendo de exclusiva responsabilidade do LOCATÁRIO a obtenção de alvarás, licenças e demais autorizações necessárias ao funcionamento, nos termos da Lei nº 8.245/91."""
    if uso_pesado:
        clausula += f"""

CLÁUSULA DE ADEQUAÇÕES ESTRUTURAIS
O LOCATÁRIO declara ciência de que eventuais adequações estruturais necessárias para o exercício da atividade serão de sua exclusiva responsabilidade, mediante autorização prévia e escrita do LOCADOR, devendo o imóvel ser devolvido nas condições originais ao término da locação."""
    clausula += "\n\nNota: Descrição baseada nas informações e imagens fornecidas pelas partes."
    return clausula

def gerar_bloco_email_imovel(imovel):
    if not imovel or not imovel.get("finalidade"):
        return ""
    linhas = ["\nDetalhes do imóvel:"]
    linhas.append(f"• Finalidade: {imovel.get('finalidade','').capitalize()}")
    if imovel.get("tipo_imovel"): linhas.append(f"• Tipo: {imovel['tipo_imovel']}")
    if imovel.get("area"):        linhas.append(f"• Área: {imovel['area']}m²")
    if imovel.get("matricula"):   linhas.append(f"• Matrícula: {imovel['matricula']}")
    fin = imovel.get("finalidade","")
    if fin == "Residencial":
        detalhes = []
        if imovel.get("quartos"):  detalhes.append(f"{imovel['quartos']} quarto(s)")
        if imovel.get("suites"):   detalhes.append(f"{imovel['suites']} suíte(s)")
        if imovel.get("banheiros"):detalhes.append(f"{imovel['banheiros']} banheiro(s)")
        if detalhes: linhas.append(f"• {' | '.join(detalhes)}")
        extras = []
        for campo in ["varanda","quintal","area_servico","cozinha"]:
            if imovel.get(campo): extras.append(campo.replace("_"," ").capitalize())
        if extras: linhas.append(f"• Cômodos: {', '.join(extras)}")
        if imovel.get("vagas"):    linhas.append(f"• Vagas: {imovel['vagas']}")
        if imovel.get("mobiliado","Não") != "Não":
            linhas.append(f"• Mobiliado: {imovel['mobiliado']}")
    elif fin == "Comercial":
        if imovel.get("salas_internas"): linhas.append(f"• Salas internas: {imovel['salas_internas']}")
        if imovel.get("banheiros"):      linhas.append(f"• Banheiros: {imovel['banheiros']}")
        extras = []
        for campo in ["recepcao","deposito","copa"]:
            if imovel.get(campo): extras.append(campo.capitalize())
        if extras: linhas.append(f"• Dependências: {', '.join(extras)}")
        if imovel.get("vagas"):           linhas.append(f"• Vagas: {imovel['vagas']}")
        if imovel.get("pe_direito"):      linhas.append(f"• Pé-direito: {imovel['pe_direito']}m")
        if imovel.get("atividade_permitida"): linhas.append(f"• Atividade: {imovel['atividade_permitida']}")
        if imovel.get("cnae"):            linhas.append(f"• CNAE: {imovel['cnae']}")
        uso = "Pesado" if imovel.get("uso_pesado") else "Leve"
        linhas.append(f"• Uso: {uso}")
    return "\n".join(linhas)

def gerar_termo_vistoria_pdf(imovel, descricao_ia, fotos_nomes):
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, HRFlowable, Table, TableStyle
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import cm
    import io as _io

    buf = _io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            leftMargin=2.5*cm, rightMargin=2.5*cm,
                            topMargin=2.5*cm, bottomMargin=2.5*cm)
    styles = getSampleStyleSheet()
    title_style  = ParagraphStyle("title",  parent=styles["Heading1"], fontSize=14, spaceAfter=4, alignment=1)
    sub_style    = ParagraphStyle("sub",    parent=styles["Normal"],   fontSize=10, spaceAfter=2, alignment=1, textColor=colors.HexColor("#5C6B7A"))
    label_style  = ParagraphStyle("label",  parent=styles["Normal"],   fontSize=10, fontName="Helvetica-Bold", spaceBefore=10, spaceAfter=2)
    body_style   = ParagraphStyle("body",   parent=styles["Normal"],   fontSize=10, spaceAfter=4, leading=14)
    note_style   = ParagraphStyle("note",   parent=styles["Normal"],   fontSize=9,  textColor=colors.HexColor("#888888"), spaceAfter=6, leading=12)
    assin_style  = ParagraphStyle("assin",  parent=styles["Normal"],   fontSize=10, spaceAfter=4)

    data_hoje = datetime.now(timezone(timedelta(hours=-3))).strftime("%d/%m/%Y")
    finalidade = imovel.get("finalidade","")
    tipo       = imovel.get("tipo_imovel","")
    area       = imovel.get("area","")
    matricula  = imovel.get("matricula","")

    story = []
    story.append(Paragraph("TERMO DE VISTORIA INICIAL", title_style))
    story.append(Paragraph("ImobFlow — Plataforma profissional para crédito imobiliário e locação", sub_style))
    story.append(HRFlowable(width="100%", thickness=1, color=colors.HexColor("#1565C0"), spaceAfter=10))

    # Dados básicos
    story.append(Paragraph("DADOS DO IMÓVEL", label_style))
    dados_tab = [
        ["Data da vistoria:", data_hoje,       "Finalidade:", finalidade],
        ["Tipo:",             tipo,             "Área:",       f"{area}m²" if area else "—"],
        ["Matrícula:",        matricula or "—", "",            ""],
    ]
    t = Table(dados_tab, colWidths=[3.5*cm, 5*cm, 3*cm, 4*cm])
    t.setStyle(TableStyle([
        ("FONTNAME",  (0,0),(-1,-1), "Helvetica"),
        ("FONTNAME",  (0,0),(0,-1),  "Helvetica-Bold"),
        ("FONTNAME",  (2,0),(2,-1),  "Helvetica-Bold"),
        ("FONTSIZE",  (0,0),(-1,-1), 9),
        ("BOTTOMPADDING",(0,0),(-1,-1), 4),
        ("TOPPADDING",   (0,0),(-1,-1), 4),
    ]))
    story.append(t)
    story.append(Spacer(1, 0.3*cm))
    story.append(HRFlowable(width="100%", thickness=0.5, color=colors.HexColor("#DDDDDD"), spaceAfter=8))

    # Descrição por cômodo
    story.append(Paragraph("ESTADO DE CONSERVAÇÃO (análise por IA)", label_style))
    story.append(Paragraph(descricao_ia.replace("\n","<br/>"), body_style))
    story.append(Paragraph(
        "⚠️ Descrição baseada nas informações e imagens fornecidas pelas partes. "
        "Não constitui laudo técnico ou perícia especializada.",
        note_style))
    story.append(HRFlowable(width="100%", thickness=0.5, color=colors.HexColor("#DDDDDD"), spaceAfter=8))

    # Fotos
    story.append(Paragraph("FOTOS ANEXADAS", label_style))
    story.append(Paragraph(f"Total de fotos anexadas: <b>{len(fotos_nomes)}</b>", body_style))
    for i, nome in enumerate(fotos_nomes, 1):
        story.append(Paragraph(f"{i}. {nome}", body_style))
    story.append(HRFlowable(width="100%", thickness=0.5, color=colors.HexColor("#DDDDDD"), spaceAfter=16))

    # Assinaturas
    story.append(Paragraph("ASSINATURAS", label_style))
    story.append(Spacer(1, 1*cm))
    assin_tab = [
        ["_______________________________", "    ", "_______________________________"],
        ["Locador",                          "    ", "Locatário"],
        ["Data: ___/___/______",             "    ", "Data: ___/___/______"],
    ]
    ta = Table(assin_tab, colWidths=[7*cm, 1.5*cm, 7*cm])
    ta.setStyle(TableStyle([
        ("FONTNAME",  (0,0),(-1,-1), "Helvetica"),
        ("FONTNAME",  (0,1),(0,1),   "Helvetica-Bold"),
        ("FONTNAME",  (2,1),(2,1),   "Helvetica-Bold"),
        ("FONTSIZE",  (0,0),(-1,-1), 9),
        ("ALIGN",     (0,0),(-1,-1), "CENTER"),
        ("BOTTOMPADDING",(0,0),(-1,-1), 4),
    ]))
    story.append(ta)

    doc.build(story)
    buf.seek(0)
    return buf.read()

def analisar_fotos_vistoria(fotos_bytes):
    """Envia fotos para Gemini e retorna descrição neutra por cômodo."""
    if not fotos_bytes:
        return "Nenhuma imagem foi anexada para análise de vistoria."
    prompt = """Você é um assistente de vistoria imobiliária.
Analise as imagens enviadas e descreva o estado de conservação visível.

REGRAS OBRIGATÓRIAS:
- Use linguagem neutra e técnica
- NUNCA afirme problemas estruturais, elétricos ou hidráulicos
- Use frases como: "Paredes aparentam bom estado de conservação."
- Use frases como: "Não foram identificadas avarias visíveis nas imagens."
- Use frases como: "Piso aparenta conservação adequada."
- Organize por cômodo identificável (se possível)
- Seja objetivo e breve

Formate assim:
[Cômodo identificado]
• Descrição neutra...

Se não for possível identificar o cômodo: use "Área não identificada".
"""
    parts = [{"text": prompt}]
    for nome, conteudo in fotos_bytes:
        b64 = base64.b64encode(conteudo).decode('utf-8')
        parts.append({"inline_data": {"mime_type": "image/jpeg", "data": b64}})
        parts.append({"text": f"Foto: {nome}"})
    try:
        return chamar_gemini(parts)
    except Exception as e:
        return f"Não foi possível analisar as imagens automaticamente. Erro: {e}"


